// Format coil data (digital outputs)
if (msg.payload && Array.isArray(msg.payload)) {
    let coilStates = {};
    msg.payload.forEach((state, index) => {
        coilStates[`Coil_${index}`] = state ? 'ON' : 'OFF';
    });

    msg.payload = {
        type: 'Coils (Digital Outputs)',
        functionCode: 'FC01',
        startAddress: 0,
        count: msg.payload.length,
        states: coilStates,
        timestamp: new Date().toISOString()
    };

    return msg;
}
return null;

// Format discrete input data (digital inputs)
if (msg.payload && Array.isArray(msg.payload)) {
    let inputStates = {};
    msg.payload.forEach((state, index) => {
        inputStates[`Input_${index}`] = state ? 'HIGH' : 'LOW';
    });

    msg.payload = {
        type: 'Discrete Inputs (Digital Inputs)',
        functionCode: 'FC02',
        startAddress: 0,
        count: msg.payload.length,
        states: inputStates,
        timestamp: new Date().toISOString()
    };

    return msg;
}
return null;

// Format input register data (analog inputs)
if (msg.payload && Array.isArray(msg.payload)) {
    let registers = {};
    msg.payload.forEach((value, index) => {
        registers[`InputReg_${index}`] = {
            decimal: value,
            hex: '0x' + value.toString(16).toUpperCase().padStart(4, '0')
        };
    });

    msg.payload = {
        type: 'Input Registers (Analog Inputs)',
        functionCode: 'FC04',
        startAddress: 0,
        count: msg.payload.length,
        registers: registers,
        timestamp: new Date().toISOString()
    };

    return msg;
}
return null;

// Format holding register data (read/write analog)
if (msg.payload && Array.isArray(msg.payload)) {
    let registers = {};
    msg.payload.forEach((value, index) => {
        registers[`HoldingReg_${index}`] = {
            decimal: value,
            hex: '0x' + value.toString(16).toUpperCase().padStart(4, '0'),
            binary: '0b' + value.toString(2).padStart(16, '0')
        };
    });

    msg.payload = {
        type: 'Holding Registers (Read/Write)',
        functionCode: 'FC03',
        startAddress: 0,
        count: msg.payload.length,
        registers: registers,
        timestamp: new Date().toISOString()
    };

    return msg;
}
return null;
